def get_all_modules():
    """Return all learning modules."""
    return LEARNING_MODULES


def get_module_by_id(module_id: str):
    """Return a single module by its ID."""
    for mod in LEARNING_MODULES:
        if mod["id"] == module_id:
            return mod
    return None


def get_modules_by_category(category: str):
    """Return all modules in a given category."""
    return [m for m in LEARNING_MODULES if m["category"] == category]


def get_quiz_for_module(module_id: str):
    """Return quiz questions for a module."""
    mod = get_module_by_id(module_id)
    if mod:
        return mod.get("quiz", [])
    return []


def get_mock_scenarios_for_module(module_id: str):
    """Return mock call scenarios for a module."""
    mod = get_module_by_id(module_id)
    if mod:
        return mod.get("mock_scenarios", [])
    return []


def grade_quiz(module_id: str, answers: dict) -> dict:
    """
    Grade a quiz submission.

    answers format: { "0": 2, "1": 0, "2": 3, ... }
      - Keys are question index (as string)
      - Values are the selected option index (0-3)

    Each quiz question has a "correct" field (int 0-3) indicating the right answer.
    """
    quiz = get_quiz_for_module(module_id)
    if not quiz:
        return {"error": "Module or quiz not found"}

    results = []
    correct_count = 0

    for idx, q in enumerate(quiz):
        q_key = str(idx)
        user_answer = answers.get(q_key)
        correct_index = q.get("correct", 0)

        try:
            user_answer_int = int(user_answer) if user_answer is not None else -1
        except (ValueError, TypeError):
            user_answer_int = -1

        is_correct = user_answer_int == correct_index

        if is_correct:
            correct_count += 1

        results.append({
            "question_index": idx,
            "question": q.get("question", ""),
            "user_answer": user_answer_int,
            "correct_answer": correct_index,
            "is_correct": is_correct,
            "explanation": q.get("explanation", "")
        })

    total = len(quiz)
    percentage = round((correct_count / total) * 100) if total > 0 else 0

    return {
        "module_id": module_id,
        "correct": correct_count,
        "total": total,
        "percentage": percentage,
        "passed": percentage >= 75,
        "results": results
    }


def get_certification_levels():
    """Return all certification levels."""
    return CERTIFICATION_LEVELS


def check_certification_eligibility(user_progress: dict) -> list:
    """
    Check which certifications a user is eligible for.

    user_progress format:
    {
        "module_id": {
            "quiz_score": 85,
            "mock_score": 78,
            "completed": True
        },
        ...
    }
    """
    eligible = []

    for cert in CERTIFICATION_LEVELS:
        all_modules_done = True
        meets_quiz = True
        meets_mock = True

        for req_mod in cert["required_modules"]:
            prog = user_progress.get(req_mod, {})
            if not prog.get("completed", False):
                all_modules_done = False
                break
            if prog.get("quiz_score", 0) < cert["min_quiz_score"]:
                meets_quiz = False
            if prog.get("mock_score", 0) < cert["min_mock_score"]:
                meets_mock = False

        if all_modules_done and meets_quiz and meets_mock:
            eligible.append(cert)

    return eligible
